# Asset filenames that should be served from the site root with an absolute
# path (so links resolve correctly from pages in sub-directories).
ASSET_BASENAMES = {
    "styles.css", "scripts.js", "logo.png",
    "favicon.ico", "favicon-16x16.png", "favicon-32x32.png",
    "android-chrome-192x192.png", "android-chrome-512x512.png",
    "apple-touch-icon.png", "site.webmanifest",
    "sitemap.xml", "robots.txt",
}


def _clean_url_rewrite(html: str) -> str:
    """Rewrite generated HTML so links use clean URLs + absolute asset paths."""

    def page_sub(m):
        attr, slug, frag = m.group(1), m.group(2), m.group(3) or ""
        if slug not in PAGE_SLUGS:
            return m.group(0)
        if slug == "index":
            return f'{attr}="/{frag}"'
        return f'{attr}="/{slug}/{frag}"'

    # href="xxx.html" / href="xxx.html#hash"  (also action="..." and src="..." just in case)
    html = re.sub(
        r'(href|action|src)="([a-z0-9-]+)\.html(#[^"]*)?"',
        page_sub,
        html,
    )

    def asset_sub(m):
        attr, name = m.group(1), m.group(2)
        if name in ASSET_BASENAMES:
            return f'{attr}="/{name}"'
        return m.group(0)

    # href="styles.css" / src="logo.png" etc. — make root-absolute.
    html = re.sub(
        r'(href|src)="([a-zA-Z0-9_.-]+\.(?:css|js|png|ico|webmanifest|xml|txt))"',
        asset_sub,
        html,
    )
    return html

