def build_nav(active=""):
    def a(page, label):
        cls = ' class="active"' if active == page else ""
        return f'<a{cls} href="{page}">{label}</a>'

    def dd(page_key, label, href, subitems, highlight):
        active_cls = " active" if active == page_key else ""
        left = "".join(
            f'<a href="{h}">{l} <span>&rsaquo;</span></a>' for h, l in subitems
        )
        return (
            f'<div class="nav-item dropdown">'
            f'<a class="dd-top{active_cls}" href="{href}">{label}</a>'
            f'<div class="mega-menu">'
            f'<div class="mega-left">{left}</div>'
            f'<div class="mega-right">{highlight}</div>'
            f'</div>'
            f'</div>'
        )

    def services_dd():
        active_cls = " active" if active == "services.html" else ""
        cats_html = ""
        panels_html = ""
        for i, (slug, label, head, desc, image, items) in enumerate(SERVICES_CATEGORIES):
            sel = " is-active" if i == 0 else ""
            cats_html += (
                f'<a class="mega-cat{sel}" data-cat="{slug}" '
                f'href="services.html#{slug}">{label}'
                f'<span class="mega-cat-arrow">&rsaquo;</span></a>'
            )
            def _item_link(it):
                if isinstance(it, tuple):
                    lbl, href = it
                    return f'<li><a href="{href}">{lbl}</a></li>'
                return f'<li><a href="services.html#{slug}">{it}</a></li>'
            items_html = "".join(_item_link(it) for it in items)
            panels_html += (
                f'<div class="mega-panel{sel}" data-panel="{slug}">'
                f'<div class="mega-panel-body">'
                f'<h4>{head}</h4>'
                f'<ul class="mega-panel-list">{items_html}</ul>'
                f'</div>'
                f'<div class="mega-panel-side">'
                f'<p class="mega-panel-desc">{desc}</p>'
                f'<img class="mega-panel-img" src="{image}" alt="{label}" loading="lazy">'
                f'</div>'
                f'</div>'
            )
        return (
            f'<div class="nav-item dropdown services-dd">'
            f'<a class="dd-top{active_cls}" href="services.html">Services</a>'
            f'<div class="mega-menu mega-services">'
            f'<div class="mega-cats">{cats_html}</div>'
            f'<div class="mega-panels">{panels_html}</div>'
            f'</div>'
            f'</div>'
        )

    parts = [
        services_dd(),
        a("talentmanagement.html", "Talent Management"),
        dd("products.html",  "Products",          "products.html",           PRODUCTS_SUB,   PRODUCTS_HIGHLIGHT),
        dd("industries.html","Industries",        "industries.html",         INDUSTRIES,     INDUSTRIES_HIGHLIGHT),
        dd("insights.html",  "Insights",          "insights.html",           INSIGHTS_SUB,   INSIGHTS_HIGHLIGHT),
        dd("about.html",     "About",             "about.html",              ABOUT_SUB,      ABOUT_HIGHLIGHT),
        dd("careers.html",   "Careers",           "careers.html",            CAREERS_SUB,    CAREERS_HIGHLIGHT),
        f'<a class="btn btn-sm{" active" if active=="contact.html" else ""}" href="contact.html">Contact us</a>',
    ]
    return "\n        ".join(parts)


