# WRITE
# --------------------------------------------------------------------------------------

def write(filename, title, active, body):
    html = _clean_url_rewrite(page(title, active, body))
    if filename == "index.html":
        out = ROOT / "index.html"
    elif filename.endswith(".html"):
        slug = filename[:-5]
        subdir = ROOT / slug
        subdir.mkdir(exist_ok=True)
        out = subdir / "index.html"
        # Remove any stale top-level <slug>.html from earlier builds so there's
        # only one canonical URL for the page.
        legacy = ROOT / filename
        if legacy.is_file():
            legacy.unlink()
    else:
        out = ROOT / filename
    out.write_text(html, encoding="utf-8")


SITE_URL = "https://www.lesdk.com"


def _canonical_url(filename: str) -> str:
    if filename == "index.html":
        return f"{SITE_URL}/"
    if filename.endswith(".html"):
        return f"{SITE_URL}/{filename[:-5]}/"
    return f"{SITE_URL}/{filename}"


def write_sitemap(pages):
    from datetime import date
    today = date.today().isoformat()
    urls = "\n".join(
        f"  <url><loc>{_canonical_url(p)}</loc><lastmod>{today}</lastmod>"
        f"<changefreq>weekly</changefreq><priority>{'1.0' if p == 'index.html' else '0.7'}</priority></url>"
        for p in pages
    )
    xml = (
        '<?xml version="1.0" encoding="UTF-8"?>\n'
        '<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">\n'
        f"{urls}\n"
        "</urlset>\n"
    )
    (ROOT / "sitemap.xml").write_text(xml, encoding="utf-8")


def write_robots():
    txt = (
        "User-agent: *\n"
        "Allow: /\n"
        f"Sitemap: {SITE_URL}/sitemap.xml\n"
    )
    (ROOT / "robots.txt").write_text(txt, encoding="utf-8")


